import React, { useEffect, useState } from "react";
import API from "../../api/api";

const FreelancerDashboard = () => {
  const user = JSON.parse(localStorage.getItem("user"));

  const [stats, setStats] = useState({
    totalProjects: 0,
    totalProposals: 0,
    acceptedProposals: 0,
    pendingProposals: 0,
  });

  const [projects, setProjects] = useState([]);

  const fetchDashboard = async () => {
    try {
      const projectsRes = await API.get("/projects");
      const proposalsRes = await API.get(
        "/proposals/freelancer/my-proposals"
      );

      const proposals = proposalsRes.data;
      const allProjects = projectsRes.data;

      // Only active projects (you can adjust status field if needed)
      const activeProjects = allProjects.filter(
        (p) => p.status === "active"
      );

      setStats({
        totalProjects: activeProjects.length,
        totalProposals: proposals.length,
        acceptedProposals: proposals.filter(
          (p) => p.status === "accepted"
        ).length,
        pendingProposals: proposals.filter(
          (p) => p.status === "pending"
        ).length,
      });

      setProjects(activeProjects);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    fetchDashboard();
  }, []);

  return (
    <div className="p-6 md:p-10 max-w-7xl mx-auto">

      {/* ================= HERO SECTION ================= */}
      <div className="mb-8">
        <h1 className="text-3xl md:text-4xl font-bold">
          Welcome back, {user?.name || "Freelancer"} 👋
        </h1>

        <p className="text-gray-500 mt-2">
          Here’s your freelancing overview and activity summary
        </p>
      </div>

      {/* ================= STATS ================= */}
      <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-10">

        <StatCard
          title="Active Projects"
          value={stats.totalProjects}
          icon="📁"
        />

        <StatCard
          title="Total Proposals"
          value={stats.totalProposals}
          icon="📨"
        />

        <StatCard
          title="Accepted"
          value={stats.acceptedProposals}
          icon="✅"
        />

        <StatCard
          title="Pending"
          value={stats.pendingProposals}
          icon="⏳"
        />

      </div>

      {/* ================= MAIN CONTENT ================= */}
      <div className="grid lg:grid-cols-3 gap-8">

        {/* LEFT SIDE */}
        <div className="lg:col-span-2">
          <h2 className="text-xl font-semibold mb-4">
            Active Projects
          </h2>

          {projects.length === 0 && (
            <div className="bg-white p-6 rounded-xl shadow text-gray-500">
              No active projects available
            </div>
          )}

          {projects.map((project) => (
            <div
              key={project.id}
              className="bg-white p-6 rounded-xl shadow mb-4 hover:shadow-md transition"
            >
              <h3 className="font-semibold text-lg">
                {project.title}
              </h3>

              <p className="text-gray-500 mt-2 line-clamp-2">
                {project.description}
              </p>

              <p className="text-green-600 font-semibold mt-3">
                ₹ {project.budget}
              </p>
            </div>
          ))}
        </div>

        {/* RIGHT SIDE */}
        <div className="bg-white p-6 rounded-xl shadow h-fit">
          <h2 className="text-xl font-semibold mb-6">
            Profile Completion
          </h2>

          <Progress label="Basic Info" value={100} />
          <Progress label="Portfolio" value={75} />
          <Progress label="Skills" value={90} />
          <Progress label="Certifications" value={40} />
        </div>

      </div>
    </div>
  );
};

/* ================= COMPONENTS ================= */

const StatCard = ({ title, value, icon }) => (
  <div className="bg-white p-6 rounded-xl shadow flex justify-between items-center hover:shadow-md transition">
    <div>
      <p className="text-gray-500 text-sm">{title}</p>
      <h2 className="text-3xl font-bold mt-1">{value}</h2>
    </div>

    <div className="bg-green-500 text-white p-3 rounded-lg text-xl">
      {icon}
    </div>
  </div>
);

const Progress = ({ label, value }) => (
  <div className="mb-5">
    <div className="flex justify-between text-sm mb-1">
      <p>{label}</p>
      <p>{value}%</p>
    </div>

    <div className="w-full bg-gray-200 h-2 rounded-full">
      <div
        className="bg-green-500 h-2 rounded-full transition-all duration-500"
        style={{ width: `${value}%` }}
      ></div>
    </div>
  </div>
);

export default FreelancerDashboard;
